import { writeOutput } from "./codegen";

const DOCS_URL =
  "https://developers.rentcast.io/reference/getting-started-guide.md";
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCof";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from RentCast API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:rentcast",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const rentcastFirewall = {",
    '  name: "rentcast",',
    '  description: "RentCast",',
    "  placeholders: {",
    `    RENTCAST_API_KEY: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.rentcast.io/v1",',
    "      auth: {",
    "        headers: {",
    '          "X-Api-Key": "${{ secrets.RENTCAST_API_KEY }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating RentCast firewall config...");
  const ts = generateTypeScript();
  writeOutput("rentcast", ts, import.meta.dirname);
}
